//
import { Registry } from '../../../../core/zc-registry';
import { cancelAnimation } from '../../../../utils/animationutils';
import { getHoverOptions } from '../../legend-event-helpers';
import { handleShadow } from '../../../../behaviours/visual-effects/brush-handles/handle-shadow';
import { getHighlightData, handlerByType } from '../size-slider/highlight-item';

let BrushD3 = Registry.getComponent('BrushD3');
function HighlightItem(mouse, data) {
    let manager = this,
        { options, chart } = manager,
        { config, highlightElement } = options,
        hoverOptions = getHoverOptions(config, 'clr'),
        hoverType = hoverOptions.type,
        //
        dt = getHighlightData(data.point, options),
        handles;

    // Show highlight element
    cancelAnimation(highlightElement);
    highlightElement.style('opacity', null);

    if (hoverType) {
        handles = handlerByType(hoverOptions, options, dt);
        BrushD3.ADD_HANDLE(handles, highlightElement);

        let handleElement = highlightElement.selectAll('g.handle--custom');
        handleShadow(hoverOptions, [handles], handleElement, chart);
    }
}

export { HighlightItem };
